namespace sv_bbe276ade56a4c6ca0bc98df5331d343.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() =>
        new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

.step-circle {
    width: 38px;
    height: 38px;
    border-width: 2px;
    border-style: solid;
    font-size: 0.9rem;
}

.step-item.future {
    opacity: 0.45;
}

.step-item.completed {
    cursor: pointer;
}

@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"></textarea>
</div>

@if (!string.IsNullOrEmpty(Error))
{
    <div class="alert alert-danger">@Error</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="OnNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string? Error { get; set; }
    [Parameter] public bool IsValidating { get; set; }
}

@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

<h4 class="mb-3">Work History</h4>

@for (var i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index + 1"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(Error))
{
    <div class="alert alert-danger">@Error</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string? Error { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);
}

@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

<h4 class="mb-3">References</h4>

@for (var i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="References[index]"
                     Index="index + 1"
                     CanRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(Error))
{
    <div class="alert alert-danger">@Error</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string? Error { get; set; }

    private void AddReference() => References.Add(new ReferenceModel());

    private void RemoveReference(int index) => References.RemoveAt(index);
}

@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

@if (SubmittedId.HasValue)
{
    <div class="text-center py-5">
        <div class="mb-3">
            <span class="display-1 text-success">&#10003;</span>
        </div>
        <h3>Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@SubmittedId</strong>.</p>
        <p class="text-muted">We'll be in touch soon. Thank you for applying!</p>
    </div>
}
else
{
    <h4 class="mb-3">Review &amp; Submit</h4>

    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 border-bottom pb-2">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                    <small class="text-muted">@r.Email &middot; @r.Phone</small>
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="alert alert-danger">@Error</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";

    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public string? Error { get; set; }
}

