{"path": "/tmp/sv-bbe276ade56a4c6ca0bc98df5331d343/Components/Apply/StepIndicator.razor", "file_text": "<nav aria-label="Application progress">
    <ol class="step-bar list-unstyled d-flex justify-content-between m-0 p-0 mb-4">
        @for (var i = 0; i < _stepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);

            <li class="step-item text-center flex-fill position-relative
                        @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "")
                        @(!isCurrent && !isCompleted ? "future" : "")"
                @onclick="() => HandleClick(step)"
                role="@(isCompleted ? "button" : "listitem")">

                <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center fw-bold
                            @(isCurrent ? "bg-primary text-white border-primary"
                              : isCompleted ? "bg-success text-white border-success"
                              : "bg-light text-muted border-secondary")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <small class="@(!isCurrent && !isCompleted ? "text-muted" : "")">@_stepNames[step]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] _stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}
"}

