toolArgs.file_text:
@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models

@if (SubmittedId.HasValue)
{
    <div class="text-center py-5">
        <div class="mb-3">
            <span class="display-1 text-success">&#10003;</span>
        </div>
        <h3>Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@SubmittedId</strong>.</p>
        <p class="text-muted">We'll be in touch soon. Thank you for applying!</p>
    </div>
}
else
{
    <h4 class="mb-3">Review &amp; Submit</h4>

    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 border-bottom pb-2">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                    <small class="text-muted">@r.Email &middot; @r.Phone</small>
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="alert alert-danger">@Error</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";

    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public string? Error { get; set; }
}

arguments.file_text:
@page "/apply"
@using sv_bbe276ade56a4c6ca0bc98df5331d343.Components.Apply
@using sv_bbe276ade56a4c6ca0bc98df5331d343.Models
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personalInfo"
                                  OnNext="HandleNext"
                                  Error="_stepError"
                                  IsValidating="_isValidating" />
                break;

            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnBack="HandleBack"
                                 OnNext="HandleNext"
                                 Error="_stepError" />
                break;

            case 2:
                <ReferencesStep References="_references"
                                OnBack="HandleBack"
                                OnNext="HandleNext"
                                Error="_stepError" />
                break;

            case 3:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnBack="HandleBack"
                                 OnNext="HandleNext"
                                 Error="_stepError" />
                break;

            case 4:
                <ReviewStep Personal="_personalInfo"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="_coverLetter"
                            OnEditSection="GoToStep"
                            OnBack="HandleBack"
                            OnSubmit="HandleSubmit"
                            IsSubmitting="_isSubmitting"
                            SubmittedId="_submittedId"
                            Error="_stepError" />
                break;
        }
    </div>
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = new() { new() };
    private readonly List<ReferenceModel> _references = new() { new(), new() };
    private string _coverLetter = "";

    private string? _stepError;
    private bool _isValidating;
    private bool _isSubmitting;
    private int? _submittedId;

    private async Task HandleNext()
    {
        _stepError = null;

        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_personalInfo.FullName) ||
                    string.IsNullOrWhiteSpace(_personalInfo.Email) ||
                    string.IsNullOrWhiteSpace(_personalInfo.Phone) ||
                    string.IsNullOrWhiteSpace(_personalInfo.Address))
                {
                    _stepError = "Please fill in all required fields.";
                    return;
                }

                _isValidating = true;
                StateHasChanged();

                try
                {
                    var emailValid = await ApplicationService.ValidateEmailAsync(_personalInfo.Email);
                    if (!emailValid)
                    {
                        _stepError = "The email address could not be validated. Please check and try again.";
                        return;
                    }
                }
                finally
                {
                    _isValidating = false;
                }
                break;

            case 1:
                if (_workEntries.Any(e =>
                        string.IsNullOrWhiteSpace(e.Company) ||
                        string.IsNullOrWhiteSpace(e.Title) ||
                        e.StartDate is null))
