+                    var emailValid = await ApplicationService.ValidateEmailAsync(_personalInfo.Email);
+                    if (!emailValid)
+                    {
+                        _stepError = "The email address could not be validated. Please check and try again.";
+                        return;
+                    }
+                }
+                finally
+                {
+                    _isValidating = false;
+                }
+                break;
+
+            case 1:
+                if (_workEntries.Any(e =>
+                        string.IsNullOrWhiteSpace(e.Company) ||
+                        string.IsNullOrWhiteSpace(e.Title) ||
+                        e.StartDate is null))
+                {
+                    _stepError = "Please fill in company, job title, and start date for every position.";
+                    return;
+                }
+                break;
+
+            case 2:
+                if (_references.Any(r =>
+                        string.IsNullOrWhiteSpace(r.Name) ||
+                        string.IsNullOrWhiteSpace(r.Relationship) ||
+                        string.IsNullOrWhiteSpace(r.Email) ||
+                        string.IsNullOrWhiteSpace(r.Phone)))
+                {
+                    _stepError = "Please fill in all fields for each reference.";
+                    return;
+                }
+                break;
+
+            case 3:
+                if (string.IsNullOrWhiteSpace(_coverLetter))
+                {
+                    _stepError = "Please write a cover letter before continuing.";
+                    return;
+                }
+                break;
+        }
+
+        _completedSteps.Add(_currentStep);
+        _currentStep++;
+    }
+
+    private void HandleBack()
+    {
+        _stepError = null;
+        if (_currentStep > 0) _currentStep--;
+    }
+
+    private void GoToStep(int step)
+    {
+        _stepError = null;
+        _currentStep = step;
+    }
+
+    private async Task HandleSubmit()
+    {
+        _stepError = null;
+        _isSubmitting = true;
+
+        try
+        {
+            var application = new JobApplication(
+                _personalInfo.ToRecord(),
+                new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
+                _references.Select(r => r.ToRecord()).ToList(),
+                _coverLetter);
+
+            _submittedId = await ApplicationService.SubmitApplicationAsync(application);
+        }
+        catch (Exception ex)
+        {
+            _stepError = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+}
